def process_graph(graph_data):
    # Create a copy of the input graph to avoid modifying the original
    graph_copy = graph_data.copy()

    # Helper to find a node by its 'name' attribute
    def find_node_by_name(g, target_name):
        for n, attrs in g.nodes(data=True):
            if attrs.get('name') == target_name:
                return n
        return None

    # Helper to recursively sum physical_capacity_bps of all PORT descendants
    def sum_port_capacity(g, start_node):
        total = 0
        stack = [start_node]
        visited = set()
        while stack:
            current = stack.pop()
            if current in visited:
                continue
            visited.add(current)
            attrs = g.nodes[current]
            if 'EK_PORT' in attrs.get('type', []):
                total += attrs.get('physical_capacity_bps', 0)
            # Traverse outgoing edges that represent containment
            for _, succ, edata in g.out_edges(current, data=True):
                if edata.get('type') == 'RK_CONTAINS':
                    stack.append(succ)
        return total

    # 1. Add the new PORT node under ju1.a4.m3
    parent_name = 'ju1.a4.m3'
    parent_node = find_node_by_name(graph_copy, parent_name)
    if parent_node is None:
        # Parent not found; return an error message
        return {
            'type': 'text',
            'data': f"Parent node with name '{parent_name}' not found.",
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }

    # Define a unique identifier for the new node (use max existing node id + 1)
    new_node_id = max(graph_copy.nodes) + 1 if graph_copy.nodes else 0
    new_node_attrs = {
        'name': 'new_EK_PORT_15',
        'type': ['EK_PORT'],
        'physical_capacity_bps': 0  # No capacity specified, default to 0
    }
    graph_copy.add_node(new_node_id, **new_node_attrs)
    # Add containment edge from parent to new node
    graph_copy.add_edge(parent_node, new_node_id, type='RK_CONTAINS')

    # 2. Rank direct child nodes of ju1.a4.m3 by total physical capacity
    child_nodes = []
    for _, succ, edata in graph_copy.out_edges(parent_node, data=True):
        if edata.get('type') == 'RK_CONTAINS':
            child_nodes.append(succ)

    ranking = []
    for child in child_nodes:
        child_name = graph_copy.nodes[child].get('name')
        total_capacity = sum_port_capacity(graph_copy, child)
        ranking.append([child_name, total_capacity])

    # Sort descending by capacity
    ranking.sort(key=lambda x: x[1], reverse=True)

    # Prepare the return object
    return_object = {
        'type': 'list',
        'data': ranking,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }
    return return_object

